--- @field public is_dive_sliding fun(m: MarioState): boolean 
--- @field public cur_obj_spawn_loot_coin_at_pos fun(m: MarioState) 
--- @field public obj_is_ground_pounding_platform fun(m: MarioState, obj: Object): boolean 
